[CmdletBinding()]
param(
  [string]$Root=(Resolve-Path (Join-Path $PSScriptRoot '../..')).Path,
  [string]$OutputRoot=(Join-Path $Root 'artifacts/dns-doh3-smoke-packages'),
  [string]$SmokeRoot=(Join-Path $Root 'artifacts/dns-doh3-three-package-smoke'),
  [switch]$SkipBuild,
  [switch]$AllowDirtySource
)
$ErrorActionPreference='Stop'
Add-Type -AssemblyName System.IO.Compression.FileSystem
function Expand-Package($archive,$destination){if(Test-Path $destination){Remove-Item $destination -Recurse -Force};New-Item -ItemType Directory -Force $destination|Out-Null;[IO.Compression.ZipFile]::ExtractToDirectory($archive,$destination);$m=Get-Content (Join-Path $destination 'protocol-lab-package.json') -Raw|ConvertFrom-Json;if($m.schemaVersion-ne'protocol-lab-package-v2'){throw "$archive is not package-v2"};$m}
function Get-Archive($name){$items=@(Get-ChildItem $OutputRoot -File -Filter $name);if($items.Count-ne1){throw "Expected one $name, found $($items.Count)."};$items[0].FullName}
if(-not$SkipBuild){& (Join-Path $PSScriptRoot 'Build-DnsDoh3PerformanceScenarioPackage.ps1') -Root $Root -OutputRoot $OutputRoot -AllowDirtySource:$AllowDirtySource;& (Join-Path $PSScriptRoot 'Build-GoDnsDoh3Package.ps1') win-x64 -Root $Root -OutputRoot $OutputRoot -AllowDirtySource:$AllowDirtySource;& (Join-Path $PSScriptRoot 'Build-GoDnsDoh3ExecutorPackage.ps1') win-x64 -Root $Root -OutputRoot $OutputRoot -AllowDirtySource:$AllowDirtySource}
if(Test-Path $SmokeRoot){Remove-Item $SmokeRoot -Recurse -Force};New-Item -ItemType Directory -Force $SmokeRoot|Out-Null
$scenarioRoot=Join-Path $SmokeRoot 'scenario';$targetRoot=Join-Path $SmokeRoot 'target';$executorRoot=Join-Path $SmokeRoot 'executor'
$scenarioManifest=Expand-Package (Get-Archive 'org.protocol-lab.components.scenario.dns-doh3-performance.0.2.0.plabpkg') $scenarioRoot
$targetManifest=Expand-Package (Get-Archive 'org.protocol-lab.components.implementation.go-dns-doh3.0.2.1.win-x64.plabpkg') $targetRoot
$executorManifest=Expand-Package (Get-Archive 'org.protocol-lab.components.executor.go-dns-doh3-executor.0.2.2.win-x64.plabpkg') $executorRoot
if($scenarioManifest.packageId-ne'org.protocol-lab.components.scenario.dns-doh3-performance'-or$targetManifest.packageId-ne'org.protocol-lab.components.implementation.go-dns-doh3'-or$executorManifest.packageId-ne'org.protocol-lab.components.executor.go-dns-doh3-executor'){throw 'Package identity mismatch.'}
$port=18533;$env:PLAB_DOH3_LISTEN="127.0.0.1:$port";$targetOut=Join-Path $SmokeRoot 'target.stdout.log';$targetErr=Join-Path $SmokeRoot 'target.stderr.log';$target=Start-Process (Join-Path $targetRoot 'bin/win-x64/go-dns-doh3.exe') -WorkingDirectory $targetRoot -RedirectStandardOutput $targetOut -RedirectStandardError $targetErr -WindowStyle Hidden -PassThru
try{
  $ready=$false;for($i=0;$i-lt50;$i++){Start-Sleep -Milliseconds 100;if($target.HasExited){throw "Target exited $($target.ExitCode): $(Get-Content $targetErr -Raw)"};if((Test-Path $targetOut)-and((Get-Content $targetOut -Raw)-match'"status":"ready"')){$ready=$true;break}};if(-not$ready){throw 'DoH3 target did not report readiness.'}
  $env:PLAB_LOAD_PROFILE_ID='secure-dns-smoke';$env:PLAB_EXECUTOR_ID='go-dns-doh3-executor';$env:PLAB_EXECUTOR_VERSION='0.2.2';$env:PLAB_LOAD_GENERATOR_ID='go-dns-doh3-load';$env:PLAB_LOAD_GENERATOR_VERSION='0.2.2';$env:PLAB_PROTOCOL='doh3';$env:PLAB_PROTOCOL_VARIANT='doh-h3-quic-v1';$env:PLAB_CONNECTIONS='1';$env:PLAB_CONCURRENCY='1';$env:PLAB_DURATION_SECONDS='5';$env:PLAB_WARMUP_SECONDS='1';$env:PLAB_REPETITION='1'
  $ids=@('dns.doh3.query.a','dns.doh3.interoperability.query.a','dns.doh3.get.a','dns.doh3.query.aaaa','dns.doh3.query.cname-chain','dns.doh3.query.large-dnssec-shaped','dns.doh3.query.nodata','dns.doh3.query.nxdomain');$summaries=@()
  foreach($id in $ids){$cell=Join-Path $SmokeRoot $id;New-Item -ItemType Directory -Force $cell|Out-Null;$env:PLAB_SCENARIO_ID=$id;$env:PLAB_PROTOCOL_VARIANT=if($id-eq'dns.doh3.interoperability.query.a'){'doh-h3-rfc8484-interoperability'}else{'doh-h3-quic-v1'};$stdout=Join-Path $cell 'load.stdout.log';$stderr=Join-Path $cell 'load.stderr.log';& (Join-Path $executorRoot 'bin/win-x64/go-dns-doh3-executor.exe') --target-address "https://127.0.0.1:$port/dns-query" --root-certificate (Join-Path $executorRoot 'certs/root.pem') --output-dir $cell 1> $stdout 2> $stderr;if($LASTEXITCODE-ne0){throw "$id executor exit $LASTEXITCODE`: $(Get-Content $stderr -Raw)"};$r=Get-Content (Join-Path $cell 'result.json') -Raw|ConvertFrom-Json;if($r.status-ne'passed'-or$r.scenarioId-ne$id-or$r.protocolProof.observedProtocol-ne'doh3'-or$r.protocolProof.quic.version-ne'v1'-or$r.protocolProof.tls.tlsVersion-ne'TLS1.3'-or$r.protocolProof.tls.alpn-ne'h3'-or$r.protocolProof.http.httpVersion-ne'HTTP/3.0'-or$r.protocolProof.fallbackDetected-or$r.metrics.completedOperations-le0-or$r.metrics.malformedOperations-ne0-or$r.metrics.retryCount-ne0-or$r.metrics.failedOperations-ne0-or$r.metrics.timedOutOperations-ne0){throw "$id result gate failed."};if(-not$r.protocolProof.tls.platformProvenance.goos-or-not$r.protocolProof.tls.platformProvenance.goarch-or-not$r.protocolProof.tls.platformProvenance.goVersion-or-not$r.protocolProof.tls.accelerationProvenance.mode){throw "$id TLS provenance gate failed."};if($r.protocolProof.http.connectionReused-ne$true-or$r.protocolProof.dns.responseCanonicalized-ne$true-or$r.protocolProof.dns.externalUpstreamUsed-ne$false){throw "$id reuse/fixture gate failed."};if($id-eq'dns.doh3.get.a' -and ($r.protocolProof.http.method-ne'GET'-or$r.protocolProof.http.getQueryEncoding-ne'base64url-unpadded'-or$r.protocolProof.http.getRequestBody-ne'absent')){throw 'GET binding gate failed.'};if($id-eq'dns.doh3.query.large-dnssec-shaped' -and ($r.protocolProof.dns.responseCanonicalLengthBytes-ne630-or$r.protocolProof.dns.dnssecSignatureValidity-ne'not-claimed')){throw 'Large fixture gate failed.'};foreach($name in @('validation.json','protocol-proof.json','dns-wire-summary.json','http-summary.json','quic-summary.json','tls-negotiation.json','result.json','dns-doh3-executor-result.json','dns-load-summary.json','dns-warmup-summary.json','executor-identity.json','load-generator-identity.json','load.stdout.log','load.stderr.log')){if(-not(Test-Path (Join-Path $cell $name))){throw "$id missing $name"}};$summaries+=@{scenarioId=$id;completedOperations=$r.metrics.completedOperations;malformedOperations=$r.metrics.malformedOperations;retryCount=$r.metrics.retryCount;failedOperations=$r.metrics.failedOperations;timedOutOperations=$r.metrics.timedOutOperations;queryLength=$r.protocolProof.dns.queryLengthBytes;responseLength=$r.protocolProof.dns.responseCanonicalLengthBytes;queryHash=$r.protocolProof.dns.queryNormalizedSha256;responseHash=$r.protocolProof.dns.responseNormalizedSha256;artifactRoot=$cell}}
  foreach($unsupported in @('dns.classic.tcp.query.a','dns.classic.udp-truncated-tcp-retry','dns.classic.udp.query.a','dns.doh2.query.a','dns.doq.query.a','dns.dot.query.a')){$u=Join-Path $SmokeRoot "unsupported/$unsupported";New-Item -ItemType Directory -Force $u|Out-Null;$env:PLAB_SCENARIO_ID=$unsupported;& (Join-Path $executorRoot 'bin/win-x64/go-dns-doh3-executor.exe') --target-address "https://127.0.0.1:$port/dns-query" --root-certificate (Join-Path $executorRoot 'certs/root.pem') --output-dir $u *> $null;if($LASTEXITCODE-ne3){throw "$unsupported expected unsupported exit 3, got $LASTEXITCODE"};$ur=Get-Content (Join-Path $u 'result.json') -Raw|ConvertFrom-Json;if($ur.status-ne'unsupported'-or$ur.scenarioId-ne$unsupported){throw "$unsupported unsupported result mismatch."}}
  $unknown=Join-Path $SmokeRoot 'unknown';New-Item -ItemType Directory -Force $unknown|Out-Null;$env:PLAB_SCENARIO_ID='dns.unknown.identity';& (Join-Path $executorRoot 'bin/win-x64/go-dns-doh3-executor.exe') --target-address "https://127.0.0.1:$port/dns-query" --root-certificate (Join-Path $executorRoot 'certs/root.pem') --output-dir $unknown *> $null;if($LASTEXITCODE-ne2){throw "Unknown identity exit $LASTEXITCODE"}
  $summaries|ConvertTo-Json -Depth 10|Set-Content (Join-Path $SmokeRoot 'smoke-summary.json') -Encoding utf8NoBOM;$summaries|ForEach-Object{Write-Host "$($_.scenarioId): completed=$($_.completedOperations) malformed=$($_.malformedOperations) retries=$($_.retryCount) failed=$($_.failedOperations) timedOut=$($_.timedOutOperations) responseBytes=$($_.responseLength)"}
}
finally{if($target-and-not$target.HasExited){Stop-Process $target.Id -Force};Remove-Item Env:PLAB_DOH3_LISTEN -ErrorAction SilentlyContinue}
